/* ===================== RENDER BLOG GRID ===================== */
const blogGrid = document.getElementById('blogGrid');

/* Ảnh Nụ luân phiên theo thứ tự card */
const nuImages = ['images/nu-1.webp','images/nu-2.webp','images/nu-3.webp','images/nu-4.webp'];

blogData.forEach((post, i) => {
  const card = document.createElement('div');
  card.className = 'blog-card reveal';
  card.style.setProperty('--i', i % 3);
  const nuSrc = nuImages[i % nuImages.length];
  const storyNum = String(i + 1).padStart(2, '0');
  card.innerHTML = `
    <div class="thumb blog-thumb-nu">
      <div class="blog-num-badge">${storyNum}</div>
      <img class="blog-nu-img" src="${nuSrc}" alt="Bé Nụ kể chuyện #${storyNum}" loading="lazy" draggable="false">
      <div class="blog-thumb-glow"></div>
    </div>
    <div class="blog-body">
      <h4>${post.title}</h4>
      <p>${post.summary}</p>
      <span class="blog-read">Đọc toàn bộ <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M5 12h14M13 6l6 6-6 6"/></svg></span>
    </div>`;
  card.addEventListener('click', () => openModal(post));
  blogGrid.appendChild(card);
});

