/* ===================== MODAL — "Đọc toàn bộ" reading experience ===================== */
const overlay = document.getElementById('modalOverlay');
const modalContent = document.getElementById('modalContent');
const modalScroll = document.getElementById('modalScroll');
const modalProgressFill = document.getElementById('modalProgressFill');
const modalCount = document.getElementById('modalCount');
const modalPrevBtn = document.getElementById('modalPrev');
const modalNextBtn = document.getElementById('modalNext');

let currentPostIndex = 0;

/* Nhận diện & định dạng từng đoạn văn cho dễ đọc:
   - Đoạn mở đầu -> "lead" (chữ lớn, dẫn nhập)
   - "Bước X — Tên bước: nội dung" -> thẻ bước có số thứ tự
   - "Tên thành phần: nội dung" -> thẻ điểm nhấn có chấm tròn
   - Còn lại -> đoạn văn thường */
function renderStoryParagraph(text, idx){
  const stepMatch = text.match(/^Bước\s+(\d+)\s*[—-]\s*([^:]+):\s*(.*)$/su);
  if(stepMatch){
    return `<div class="story-step">
      <div class="story-step-num">${stepMatch[1].padStart(2,'0')}</div>
      <div class="story-step-body">
        <h5>${stepMatch[2].trim()}</h5>
        <p>${stepMatch[3].trim()}</p>
      </div>
    </div>`;
  }
  const labelMatch = idx > 0 ? text.match(/^([^:]{2,46}):\s+(.*)$/su) : null;
  if(labelMatch){
    return `<div class="story-point">
      <span class="story-point-dot" aria-hidden="true"></span>
      <div class="story-point-body">
        <h5>${labelMatch[1].trim()}</h5>
        <p>${labelMatch[2].trim()}</p>
      </div>
    </div>`;
  }
  if(idx === 0){
    return `<p class="story-lead">${text}</p>`;
  }
  return `<p>${text}</p>`;
}

function estimateReadMins(post){
  const words = post.full.join(' ').split(/\s+/).filter(Boolean).length;
  return Math.max(1, Math.round(words / 120));
}

function openModal(post){
  const postIdx = blogData.indexOf(post);
  currentPostIndex = postIdx > -1 ? postIdx : 0;
  renderModal(currentPostIndex);
  overlay.classList.add('open');
  document.body.style.overflow = 'hidden';
}

function renderModal(index){
  const post = blogData[index];
  const storyNum = String(index + 1).padStart(2, '0');
  const readMins = estimateReadMins(post);
  const tagsHtml = post.use.map(t => `<span>${t}</span>`).join('');
  const hashHtml = post.hashtags.length ? `<div class="modal-hash">${post.hashtags.map(h=>`<span>${h}</span>`).join('')}</div>` : '';

  modalContent.innerHTML = `
    <div class="modal-head">
      <div class="modal-head-top">
        <span class="modal-story-badge">${storyNum}</span>
        <div class="modal-head-meta">
          <span class="modal-eyebrow">Chuyên mục · Nụ kể chuyện</span>
          <span class="id-tag">${post.id}</span>
        </div>
      </div>
      <h3>${post.title}</h3>
      <div class="modal-meta-row">
        <span class="modal-meta-item">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="9"/><path d="M12 7v5l3 3"/></svg>
          ${readMins} phút đọc
        </span>
        <span class="modal-meta-dot">•</span>
        <span class="modal-meta-item">Câu chuyện ${index + 1}/${blogData.length}</span>
      </div>
    </div>
    <div class="modal-divider" aria-hidden="true"><span>❁</span></div>
    <div class="full-text">${post.full.map((p, i) => renderStoryParagraph(p, i)).join('')}</div>
    <div class="modal-tags">${tagsHtml}</div>
    ${hashHtml}
  `;
  modalCount.textContent = `${index + 1} / ${blogData.length}`;
  modalPrevBtn.disabled = index === 0;
  modalNextBtn.disabled = index === blogData.length - 1;
  modalScroll.scrollTop = 0;
  updateModalProgress();
}

function updateModalProgress(){
  const { scrollTop, scrollHeight, clientHeight } = modalScroll;
  const max = scrollHeight - clientHeight;
  const pct = max > 0 ? (scrollTop / max) * 100 : 0;
  modalProgressFill.style.width = pct + '%';
}
modalScroll.addEventListener('scroll', updateModalProgress);

function goToStory(delta){
  const next = currentPostIndex + delta;
  if(next < 0 || next >= blogData.length) return;
  currentPostIndex = next;
  renderModal(currentPostIndex);
}
modalPrevBtn.addEventListener('click', () => goToStory(-1));
modalNextBtn.addEventListener('click', () => goToStory(1));

function closeModal(){
  overlay.classList.remove('open');
  document.body.style.overflow = '';
}
document.getElementById('modalClose').addEventListener('click', closeModal);
overlay.addEventListener('click', e => { if(e.target === overlay) closeModal(); });
document.addEventListener('keydown', e => {
  if(!overlay.classList.contains('open')) return;
  if(e.key === 'Escape') closeModal();
  if(e.key === 'ArrowRight') goToStory(1);
  if(e.key === 'ArrowLeft') goToStory(-1);
});

