/* ===================== NAV: scroll state + mobile burger ===================== */
const siteNav = document.getElementById('siteNav');
const navLinks = document.getElementById('navLinks');
const burgerBtn = document.getElementById('burgerBtn');
const toTop = document.getElementById('toTop');

/* ---- Bộ điều phối scroll dùng chung: gộp mọi việc cần làm mỗi khi cuộn
   vào MỘT requestAnimationFrame duy nhất thay vì nhiều listener rời rạc.
   Giúp giảm số lần đọc/ghi layout mỗi khung hình -> cuộn mượt hơn hẳn,
   nhất là trên máy yếu / trang dài nhiều hiệu ứng. ---- */
const __scrollCallbacks = [];
function onEveryScroll(fn){ __scrollCallbacks.push(fn); }
let __scrollTicking = false;
function __runScrollCallbacks(){
  const y = window.scrollY;
  for(let i=0;i<__scrollCallbacks.length;i++) __scrollCallbacks[i](y);
  __scrollTicking = false;
}
window.addEventListener('scroll', () => {
  if(!__scrollTicking){
    __scrollTicking = true;
    requestAnimationFrame(__runScrollCallbacks);
  }
}, { passive: true });

function onScroll(y){
  siteNav.classList.toggle('scrolled', y > 60);
  toTop.classList.toggle('show', y > 600);
}
onEveryScroll(onScroll);
onScroll(window.scrollY);

burgerBtn.addEventListener('click', () => navLinks.classList.toggle('open'));
navLinks.querySelectorAll('a').forEach(a => a.addEventListener('click', () => navLinks.classList.remove('open')));
toTop.addEventListener('click', () => window.scrollTo({top:0, behavior:'smooth'}));

/* ===================== MINI GAME: MỞ LINK PLAYCANVAS ===================== */
(function(){
  /* Lưu ý: PlayCanvas chặn nhúng iframe ở mọi trang (X-Frame-Options: DENY),
     nên trên máy tính mục này sẽ mở thẳng link ở tab mới thay vì nhúng vào trang. */
  const GAME_URL = 'https://launch.playcanvas.com/2518553?debug=true';
  const gameOverlay = document.getElementById('gameOverlay');
  const gameMobileBlock = document.getElementById('gameMobileBlock');
  const miniGameLink = document.getElementById('miniGameLink');
  const gameBackBtnInline = document.getElementById('gameBackBtnInline');
  if(!gameOverlay || !miniGameLink) return;

  /* Phát hiện điện thoại (không chặn tablet/laptop cảm ứng lớn):
     dựa vào user-agent của các dòng máy điện thoại phổ biến,
     kết hợp kiểm tra bề rộng màn hình nhỏ để bắt các trường hợp còn sót. */
  function isPhoneDevice(){
    const ua = navigator.userAgent || navigator.vendor || '';
    const uaIsPhone = /iPhone|iPod|Android.*Mobile|Windows Phone|BlackBerry|IEMobile|Opera Mini/i.test(ua);
    const narrowTouch = window.matchMedia('(pointer:coarse)').matches && Math.min(window.innerWidth, window.innerHeight) <= 600;
    return uaIsPhone || narrowTouch;
  }

  function showMobileBlock(){
    gameOverlay.classList.add('open');
    gameOverlay.setAttribute('aria-hidden', 'false');
    gameMobileBlock.classList.add('show');
    document.body.style.overflow = 'hidden';
  }

  function closeMobileBlock(){
    gameOverlay.classList.remove('open');
    gameOverlay.setAttribute('aria-hidden', 'true');
    gameMobileBlock.classList.remove('show');
    document.body.style.overflow = '';
  }

  miniGameLink.addEventListener('click', (e) => {
    e.preventDefault();
    if(isPhoneDevice()){
      showMobileBlock();
    } else {
      window.open(GAME_URL, '_blank', 'noopener,noreferrer');
    }
  });

  if(gameBackBtnInline) gameBackBtnInline.addEventListener('click', closeMobileBlock);
  document.addEventListener('keydown', (e) => {
    if(e.key === 'Escape' && gameOverlay.classList.contains('open')) closeMobileBlock();
  });
})();

/* ===================== NAV: active link tracking ===================== */
const navAnchorLinks = Array.from(navLinks.querySelectorAll('a[href^="#"]'));
const trackedSections = navAnchorLinks
  .map(a => document.querySelector(a.getAttribute('href')))
  .filter(Boolean);

function setActiveNav(id){
  navAnchorLinks.forEach(a => a.classList.toggle('active', a.getAttribute('href') === '#' + id));
}
const navObserver = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if(entry.isIntersecting) setActiveNav(entry.target.id);
  });
}, { threshold: 0, rootMargin: '-45% 0px -50% 0px' });
trackedSections.forEach(sec => navObserver.observe(sec));



