/* ===================== PROCESS TABS ===================== */
const procTabs = document.querySelectorAll('.proc-tab');
const procViews = document.querySelectorAll('.proc-view');
const progressSpans = document.querySelectorAll('#procProgress span');
let procIndex = 0, procTimer;

function setStep(i){
  procIndex = i;
  procTabs.forEach(t => t.classList.toggle('active', +t.dataset.step === i));
  procViews.forEach(v => v.classList.toggle('active', +v.dataset.view === i));
  progressSpans.forEach((s, idx) => s.classList.toggle('done', idx <= i));
}
procTabs.forEach(tab => {
  tab.addEventListener('click', () => { setStep(+tab.dataset.step); restartAutoplay(); });
});

function restartAutoplay(){
  clearInterval(procTimer);
  procTimer = setInterval(() => { setStep((procIndex+1) % procViews.length); }, 5200);
}
if(!prefersReduced) restartAutoplay();

/* ===================== PARALLAX RAYS ON HERO ===================== */
const heroRays = document.querySelector('.hero .hero-rays');
if(!prefersReduced && heroRays){
  heroRays.style.willChange = 'transform';
  function updateRays(y){
    if(y < window.innerHeight){
      heroRays.style.transform = `translateY(${y*0.15}px)`;
    }
  }
  onEveryScroll(updateRays);
}

/* ===================== NAV: smooth scroll fix ===================== */
document.querySelectorAll('a[href^="#"]').forEach(function(anchor) {
  anchor.addEventListener('click', function(e) {
    var targetId = this.getAttribute('href');
    if(targetId === '#') { e.preventDefault(); window.scrollTo({top:0,behavior:'smooth'}); return; }
    var target = document.querySelector(targetId);
    if(target) {
      e.preventDefault();
      var navHeight = document.getElementById('siteNav').offsetHeight;
      var targetPos = target.getBoundingClientRect().top + window.scrollY - navHeight - 8;
      window.scrollTo({ top: targetPos, behavior: 'smooth' });
      document.getElementById('navLinks').classList.remove('open');
    }
  });
});

