/* ===================== 3D TILT: SẢN PHẨM & NGUYÊN LIỆU — chạm là phản hồi ngay, di chuyển mượt ===================== */
(function(){
  if(prefersReduced || window.matchMedia('(hover: none)').matches) return;
  const tiltEls = document.querySelectorAll('.prod-card, .ing-card.ing-photo');

  tiltEls.forEach(el => {
    let targetRX = 0, targetRY = 0, targetMX = 50, targetMY = 50, targetLift = 0;
    let curRX = 0, curRY = 0, curMX = 50, curMY = 50, curLift = 0;
    let rafId = null;
    let hovering = false;

    function computeFromEvent(e){
      const r = el.getBoundingClientRect();
      const px = Math.min(1, Math.max(0, (e.clientX - r.left) / r.width));
      const py = Math.min(1, Math.max(0, (e.clientY - r.top) / r.height));
      targetRY = (px - 0.5) * 14;
      targetRX = (0.5 - py) * 14;
      targetMX = px * 100;
      targetMY = py * 100;
      targetLift = -10;
    }

    function apply(rx, ry, mx, my, lift){
      el.style.transform = `translateY(${lift}px) perspective(900px) rotateX(${rx}deg) rotateY(${ry}deg)`;
      el.style.setProperty('--mx', mx + '%');
      el.style.setProperty('--my', my + '%');
    }

    function loop(){
      // Ease vừa phải khi di chuyển trong card: đủ nhanh để theo kịp tay,
      // đủ chậm để chuyển động không giật cứng theo từng pixel.
      const ease = 0.22;
      curRX += (targetRX - curRX) * ease;
      curRY += (targetRY - curRY) * ease;
      curMX += (targetMX - curMX) * ease;
      curMY += (targetMY - curMY) * ease;
      curLift += (targetLift - curLift) * ease;
      apply(curRX, curRY, curMX, curMY, curLift);

      const settled = Math.abs(targetRX-curRX)<0.05 && Math.abs(targetRY-curRY)<0.05 && Math.abs(targetLift-curLift)<0.05;
      if(hovering && !settled){
        rafId = requestAnimationFrame(loop);
      } else {
        rafId = null;
      }
    }

    function ensureLoop(){
      if(rafId === null) rafId = requestAnimationFrame(loop);
    }

    el.addEventListener('mouseenter', (e) => {
      hovering = true;
      el.classList.add('tilting');
      el.style.transition = 'none'; // tắt transition CSS để JS điều khiển ngay, không chờ
      computeFromEvent(e);
      // Chạm vào là đổi ngay: snap thẳng tới target, không lerp đuổi dần
      curRX = targetRX; curRY = targetRY;
      curMX = targetMX; curMY = targetMY;
      curLift = targetLift;
      apply(curRX, curRY, curMX, curMY, curLift);
    });
    el.addEventListener('mousemove', (e) => {
      computeFromEvent(e);
      ensureLoop();
    });
    el.addEventListener('mouseleave', () => {
      hovering = false;
      if(rafId !== null){ cancelAnimationFrame(rafId); rafId = null; }
      el.classList.remove('tilting');
      // Trả về vị trí gốc bằng CSS transition mượt, đáng tin cậy hơn lerp lúc rời chuột
      el.style.transition = 'transform .45s cubic-bezier(.25,.8,.4,1)';
      curRX = 0; curRY = 0; curMX = 50; curMY = 50; curLift = 0;
      apply(0, 0, 50, 50, 0);
    });
  });
})();

