/* ================================================================
   🌌 SMOOTH FINAL — bộ duy nhất, không xung đột
   ================================================================ */
(function () {
  'use strict';

  var reduced = window.matchMedia('(prefers-reduced-motion:reduce)').matches;

  /* ── Scroll progress bar ── */
  var bar = document.createElement('div');
  bar.style.cssText =
    'position:fixed;top:0;left:0;width:100%;height:3px;z-index:9999;' +
    'transform:scaleX(0);transform-origin:left center;pointer-events:none;' +
    'background:linear-gradient(90deg,#C2469F,#D9AE6C,#9B6FCF);' +
    'box-shadow:0 0 5px rgba(194,70,159,.4);will-change:transform;';
  document.body.prepend(bar);

  var rafPending = false;
  function updateBar() {
    var max = document.documentElement.scrollHeight - window.innerHeight;
    bar.style.transform = 'scaleX(' + (max > 0 ? (window.scrollY / max) : 0) + ')';
  }
  if (typeof onEveryScroll === 'function') {
    onEveryScroll(updateBar);
  } else {
    function onScroll() {
      if (!rafPending) {
        rafPending = true;
        requestAnimationFrame(function () { updateBar(); rafPending = false; });
      }
    }
    window.addEventListener('scroll', onScroll, { passive: true });
  }
  updateBar();

  if (reduced) return;

  /* ── Nebula blobs & Star canvas — đã tắt (hiệu ứng cố định che nội dung) ── */
  // (disabled)

  /* ── 2-WAY REVEAL — observer duy nhất ──
     Nguyên tắc:
     - Hiệu ứng lặp lại mỗi lần cuộn qua: rời khung hình → ẩn, cuộn lại → hiện
       lại mượt mà (không unobserve).
     - Vùng đệm (rootMargin) được nới RỘNG hơn hẳn so với trước ở cả 2 phía,
       để việc bật "in-view"/"out-view" chỉ xảy ra khi phần tử đã thực sự đi
       xa khỏi khung hình — tránh hiện tượng giật/nhấp nháy khi phần tử đứng
       lửng lơ ngay sát mép trong lúc người dùng dừng cuộn.
     - Margin trên (+18%) được nới rộng thêm: nội dung chỉ thực sự biến mất
       khi đã cuộn qua khỏi mép trên một khoảng đủ xa, thay vì biến mất ngay
       khi vừa chạm mép — đây là phần được tăng thêm theo yêu cầu.
     - threshold mảng nhỏ [0, 0.05, 0.12]: vẫn bắt được ngay cả khi cuộn rất
       nhanh, chỉ lướt qua trong vài khung hình.
  ── */
  var SEL = '.reveal,.reveal-scale,.reveal-left,.reveal-right,.reveal-ben';
  var els = Array.from(document.querySelectorAll(SEL));

  /* Stagger trong parent .stagger */
  els.forEach(function (el) {
    var p = el.closest('.stagger');
    if (p) {
      var sibs = Array.from(p.querySelectorAll(SEL));
      var idx = sibs.indexOf(el);
      if (idx > 0) el.style.transitionDelay = (idx * 0.08) + 's';
    }
  });

  var io = new IntersectionObserver(function (entries) {
    entries.forEach(function (e) {
      var el = e.target;
      if (e.isIntersecting) {
        el.classList.remove('out-view');
        el.classList.add('in-view');
      } else if (el.classList.contains('in-view')) {
        el.classList.remove('in-view');
        el.classList.add('out-view');
      }
      /* Chưa từng hiện → giữ opacity:0, không thêm out-view */
    });
  }, {
    threshold: [0, 0.08, 0.2],
    /* Trước đây là '18% 0px -18% 0px': cả 2 mép trên/dưới đều bị thu hẹp 18%,
       khiến vùng "được tính là đang trong khung hình" bị đẩy lệch hẳn lên trên.
       Hệ quả: những khối nằm gần cuối section/cuối trang không bao giờ lọt đủ
       sâu vào vùng này trước khi hết chỗ để cuộn tiếp => class "in-view" không
       bao giờ được thêm vào => hiệu ứng đứng im ở opacity:0, giống như "cuộn
       xuống mà không thấy hiệu ứng xuất hiện". Giảm biên độ này lại để phần tử
       chỉ cần chạm nhẹ vào khung hình là đã hiện ra.
    */
    rootMargin: '0px 0px -10% 0px'
  });

  els.forEach(function (el) { io.observe(el); });

  /* ── Section aura nhẹ ── */
  var auraMap = {
    'san-pham':    'rgba(194,70,159,.055)',
    'cong-dung':   'rgba(150,80,200,.065)',
    'nguyen-lieu': 'rgba(217,174,108,.055)',
    'quy-trinh':   'rgba(100,160,230,.060)',
  };
  Object.keys(auraMap).forEach(function (id) {
    var sec = document.getElementById(id);
    if (!sec) return;
    var aura = document.createElement('div');
    aura.style.cssText =
      'position:absolute;inset:0;pointer-events:none;z-index:0;opacity:0;' +
      'transition:opacity 1.4s ease;' +
      'background:radial-gradient(ellipse at 50% 50%,' + auraMap[id] + ' 0%,transparent 72%);';
    if (getComputedStyle(sec).position === 'static') sec.style.position = 'relative';
    sec.appendChild(aura);
    new IntersectionObserver(function (entries) {
      aura.style.opacity = entries[0].isIntersecting ? '1' : '0';
    }, { threshold: 0.06 }).observe(sec);
  });

})();

/* ============ SHAPE SECTION — tab switcher ============ */
(function(){
  var tabs = document.querySelectorAll('.sh-tab, .sh-cta');
  var panes = document.querySelectorAll('.sh-pane');
  var tabBtns = document.querySelectorAll('.sh-tab');
  var switching = false;

  function switchTab(target){
    if(switching) return;
    var currentPane = document.querySelector('.sh-pane.active');
    if(currentPane){
      var currentId = currentPane.id.replace('sh-pane-','');
      if(currentId === target) return;
    }
    switching = true;

    // Fade out current pane first
    if(currentPane){
      currentPane.style.transition = 'opacity .35s ease, transform .35s ease';
      currentPane.style.opacity = '0';
      currentPane.style.transform = 'translateY(-8px)';
    }

    setTimeout(function(){
      tabBtns.forEach(function(b){
        b.classList.toggle('active', b.dataset.tab === target);
      });
      panes.forEach(function(p){
        var id = p.id.replace('sh-pane-','');
        if(id === target){
          p.style.opacity = '';
          p.style.transform = '';
          p.style.transition = '';
          p.classList.add('active');
        } else {
          p.style.opacity = '';
          p.style.transform = '';
          p.style.transition = '';
          p.classList.remove('active');
        }
      });
      switching = false;
    }, 360);
  }

  tabs.forEach(function(btn){
    btn.addEventListener('click', function(){
      var t = btn.dataset.tab;
      if(t) switchTab(t);
    });
  });
})();

/* ============ NỤ CHUYỂN ĐỘNG — hoạt họa 151 khung, bấm để tương tác + cuộn chuột để xem ============ */
(function () {
  var pin = document.getElementById('scPin');
  if (!pin) return;

  var stage      = document.getElementById('scStage');
  var canvas     = document.getElementById('scCanvas');
  var ctx        = canvas.getContext('2d');
  var loading    = document.getElementById('scLoading');
  var loadingPct = document.getElementById('scLoadingPct');
  var dragHint   = document.getElementById('scDragHint');
  var touchHint  = document.getElementById('scTouchHint');
  var activeBadge = document.getElementById('scActiveBadge');
  var rangeEl    = document.getElementById('scRange');

  /* Thiết bị cảm ứng (điện thoại/tablet) không có sự kiện cuộn chuột (wheel)
     -> dùng thanh kéo (range slider) thay thế, ẩn gợi ý "chuột" đi */
  var isTouch = window.matchMedia && (
    window.matchMedia('(hover: none) and (pointer: coarse)').matches
  ) || ('ontouchstart' in window) || (navigator.maxTouchPoints > 0);
  if (isTouch && pin) pin.classList.add('is-touch');

  var TOTAL = 151;
  var pendingFrame = 0;
  var frameRafId = null;
  function flushPendingFrame(){
    frameRafId = null;
    setFrame(pendingFrame);
  }

  function frameSrc(i) {
    var n = String(i + 1).padStart(4, '0');
    return 'images/scroll-frames/frame_' + n + '.jpg';
  }

  var images = new Array(TOTAL);
  var loadedCount = 0;
  var currentFrame = 0;
  var isReady = false;
  var isActive = false;

  /* ---------- Canvas draw (cover-fit, DPR aware) ---------- */
  var dpr = Math.min(window.devicePixelRatio || 1, 2);

  function sizeCanvas() {
    var rect = canvas.getBoundingClientRect();
    canvas.width  = Math.round(rect.width * dpr);
    canvas.height = Math.round(rect.height * dpr);
  }

  function drawFrame(i) {
    var img = images[i];
    if (!img || !img.complete || !img.naturalWidth) return;
    var cw = canvas.width, ch = canvas.height;
    var iw = img.naturalWidth, ih = img.naturalHeight;
    var cr = cw / ch, ir = iw / ih;
    var sx, sy, sw, sh;
    if (ir > cr) { sh = ih; sw = ih * cr; sx = (iw - sw) / 2; sy = 0; }
    else { sw = iw; sh = iw / cr; sx = 0; sy = (ih - sh) / 2; }
    ctx.clearRect(0, 0, cw, ch);
    ctx.drawImage(img, sx, sy, sw, sh, 0, 0, cw, ch);
  }

  function setFrame(i) {
    i = Math.max(0, Math.min(TOTAL - 1, Math.round(i)));
    currentFrame = i;
    drawFrame(i);
    if (stage) stage.setAttribute('aria-valuenow', String(i));
    if (rangeEl && Number(rangeEl.value) !== i) rangeEl.value = String(i);
    updateRangeFill();
  }

  /* Tô màu phần đã kéo qua trên thanh trượt để dễ nhìn hơn */
  function updateRangeFill() {
    if (!rangeEl) return;
    var pct = (Number(rangeEl.value) / (TOTAL - 1)) * 100;
    rangeEl.style.background =
      'linear-gradient(90deg, var(--gold-deep) 0%, var(--gold-deep) ' + pct + '%, rgba(74,37,102,.16) ' + pct + '%, rgba(74,37,102,.16) 100%)';
  }

  /* ---------- Preload ---------- */
  function updateLoadingUI() {
    var pct = Math.round((loadedCount / TOTAL) * 100);
    loadingPct.textContent = pct + '%';
    var firstReady = images[0] && images[0].complete && images[0].naturalWidth;
    if (firstReady && !isReady) {
      isReady = true;
      loading.classList.add('is-hidden');
      sizeCanvas();
      setFrame(0);
    }
    if (loadedCount >= TOTAL) {
      loading.classList.add('is-hidden');
    }
  }

  function preload() {
    /* Frame đầu tiên tải trước để hiển thị ngay khi sẵn sàng */
    var first = new Image();
    first.decoding = 'async';
    first.onload = first.onerror = function () {
      loadedCount++;
      updateLoadingUI();
      if (0 === currentFrame && isReady) drawFrame(0);
    };
    first.src = frameSrc(0);
    images[0] = first;

    for (var i = 1; i < TOTAL; i++) {
      (function (idx) {
        var img = new Image();
        img.decoding = 'async';
        img.onload = img.onerror = function () {
          loadedCount++;
          updateLoadingUI();
          if (idx === currentFrame && isReady) drawFrame(idx);
        };
        img.src = frameSrc(idx);
        images[idx] = img;
      })(i);
    }
  }

  /* ---------- Bấm vào khung hình để "tương tác", rồi cuộn chuột để lật khung ---------- */
  var hintDismissed = false;
  function dismissHint() {
    if (hintDismissed) return;
    hintDismissed = true;
    if (dragHint) dragHint.classList.add('is-hidden');
    if (touchHint) touchHint.classList.add('is-hidden');
  }

  function activateStage() {
    if (isActive) return;
    isActive = true;
    dismissHint();
    stage.classList.add('is-active');
    if (activeBadge) activeBadge.classList.add('is-visible');
  }
  function deactivateStage() {
    if (!isActive) return;
    isActive = false;
    stage.classList.remove('is-active');
    if (activeBadge) activeBadge.classList.remove('is-visible');
  }

  /* Bấm vào khung hình -> kích hoạt (chặn không cho click này lan ra ngoài rồi tắt ngay) */
  stage.addEventListener('click', function (e) {
    e.stopPropagation();
    activateStage();
  });
  stage.addEventListener('keydown', function (e) {
    if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); activateStage(); }
  });

  /* Bấm ra ngoài khung hình -> tắt tương tác, trang có thể lướt lên/xuống bình thường */
  document.addEventListener('click', function (e) {
    if (isActive && !stage.contains(e.target)) deactivateStage();
  });
  document.addEventListener('keydown', function (e) {
    if (isActive && e.key === 'Escape') deactivateStage();
  });

  /* Khi đang tương tác: cuộn/phóng chuột trên khung hình sẽ lật khung thay vì cuộn trang.
     Khi chưa kích hoạt: cuộn chuột đi xuyên qua, trang lướt bình thường. */
  stage.addEventListener('wheel', function (e) {
    if (!isActive || !isReady) return;
    e.preventDefault();
    var step = Math.sign(e.deltaY) * Math.max(1, Math.round(Math.abs(e.deltaY) / 12));
    pendingFrame = Math.max(0, Math.min(TOTAL - 1, currentFrame + step));
    if (!frameRafId) frameRafId = requestAnimationFrame(flushPendingFrame);
  }, { passive: false });

  window.addEventListener('resize', function () {
    dpr = Math.min(window.devicePixelRatio || 1, 2);
    sizeCanvas();
    drawFrame(currentFrame);
  });

  /* ---------- Thanh kéo (scrub bar) — dành cho thiết bị cảm ứng ---------- */
  if (rangeEl) {
    rangeEl.addEventListener('input', function () {
      dismissHint();
      if (activeBadge) activeBadge.classList.remove('is-visible');
      setFrame(Number(rangeEl.value));
    });
    updateRangeFill();
  }

  /* ---------- Init ----------
     Chỉ bắt đầu tải 151 khung hình khi khối này thực sự sắp lọt vào màn hình,
     thay vì tải hết ngay lúc trang vừa load. Trước đây preload() được gọi
     ngay lập tức => 151 request ảnh bắn ra cùng lúc với ảnh hero/banner,
     tranh băng thông + luồng chính của trình duyệt => cả trang bị giật/lag
     ngay từ đầu, kể cả khi người dùng chưa cuộn tới khu vực này. */
  sizeCanvas();
  var __preloadStarted = false;
  function __startPreloadOnce() {
    if (__preloadStarted) return;
    __preloadStarted = true;
    preload();
  }
  if ('IntersectionObserver' in window) {
    var __preloadIO = new IntersectionObserver(function (entries) {
      entries.forEach(function (entry) {
        if (entry.isIntersecting) {
          __startPreloadOnce();
          __preloadIO.disconnect();
        }
      });
    }, { rootMargin: '800px 0px 800px 0px' }); // tải trước một chút trước khi tới, cho kịp
    __preloadIO.observe(pin);
  } else {
    __startPreloadOnce();
  }
})();
